 12	import { isEmpty } from '@kubevirt-utils/utils/utils';
 13	import { Button, Grid, GridItem, Truncate } from '@patternfly/react-core';
 14	import { MinusCircleIcon } from '@patternfly/react-icons';
 15	
 16	import { AuthKeyRow } from '../../utils/types';
 17	import AddProjectAuthKeyButton from '../AddProjectAuthKeyButton/AddProjectAuthKeyButton';
 18	
 19	import './SSHAuthKeyRow.scss';
 20	
 21	type SSHAuthKeyRowProps = {
 22	  isRemoveDisabled: boolean;
 23	  onAuthKeyChange: (updatedKey: AuthKeyRow) => void;
 24	  onAuthKeyDelete: (keyToRemove: AuthKeyRow) => void;
 25	  row: AuthKeyRow;
 26	  selectableProjects: string[];
 27	};
 28	
 29	const SSHAuthKeyRow: FC<SSHAuthKeyRowProps> = ({
 30	  isRemoveDisabled,
 31	  onAuthKeyChange,
 32	  onAuthKeyDelete,
 33	  row,
 34	  selectableProjects,
 35	}) => {
 36	  const { t } = useKubevirtTranslation();
 37	  const { projectName, secretName } = row;
 38	
 39	  const onSubmit = useCallback(
 40	    (sshDetails: SSHSecretDetails) => {
 41	      const { secretOption, sshPubKey, sshSecretName } = sshDetails;
 42	
 43	      if (isEqualObject(sshDetails?.sshSecretName, secretName)) {
 44	        return Promise.resolve();
 45	      }
 46	
 47	      if (secretOption === SecretSelectionOption.none && !isEmpty(secretName)) {
 48	        const updatedRow = { ...row, secretName: '' };
 49	        onAuthKeyChange(updatedRow);
 50	        return Promise.resolve();
 51	      }
 52	
 53	      if (
 54	        secretOption === SecretSelectionOption.useExisting &&
 55	        secretName !== sshSecretName &&
 56	        !isEmpty(sshSecretName)
 57	      ) {
 58	        const updatedRow = { ...row, secretName: sshSecretName };
 59	        onAuthKeyChange(updatedRow);
 60	        return Promise.resolve();
 61	      }
 62	
 63	      if (
 64	        secretOption === SecretSelectionOption.addNew &&
 65	        !isEmpty(sshPubKey) &&
 66	        !isEmpty(sshSecretName)
 67	      ) {
 68	        const updatedRow = { ...row, secretName: sshSecretName };
 69	        onAuthKeyChange(updatedRow);
 70	        return createSSHSecret(sshPubKey, sshSecretName, projectName);
 71	      }
 72	    },
 73	    [secretName, row, onAuthKeyChange, projectName],
 74	  );
 75	
 76	  return (
 77	    <Grid className="pf-v6-u-mb-sm">
 78	      <GridItem className="ssh-auth-row__project-name" span={5}>
 79	        {isEmpty(secretName) ? (
 80	          <InlineFilterSelect
 81	            options={selectableProjects?.sort().map((opt) => ({
 82	              children: opt,
 83	              groupVersionKind: modelToGroupVersionKind(ProjectModel),
 84	              value: opt,
 85	            }))}
 86	            selected={projectName}
 87	            setSelected={(newProject) => onAuthKeyChange({ ...row, projectName: newProject })}
 88	            toggleProps={{ isFullWidth: true, placeholder: t('Select project') }}
 89	          />
 90	        ) : (
 91	          <Truncate content={projectName} />
 92	        )}
 93	      </GridItem>
 94	      <GridItem span={1} />
 95	      <GridItem className="ssh-auth-row__edit-button" span={5}>
 96	        <AddProjectAuthKeyButton
 97	          onSubmit={onSubmit}
 98	          secretName={secretName}
 99	          selectedProject={projectName}
100	        />
101	      </GridItem>
102	      <GridItem span={1}>
103	        <Button
104	          isDisabled={isRemoveDisabled}
105	          isInline
106	          onClick={() => onAuthKeyDelete(row)}
107	          variant="plain"
108	        >
109	          <MinusCircleIcon />
110	        </Button>
111	      </GridItem>
112	    </Grid>
113	  );
114	};
115	
116	export default SSHAuthKeyRow;

